			containerLabel = "init container"
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsNonRoot != nil && *container.SecurityContext.RunAsNonRoot {
			// Container explicitly sets runAsNonRoot=true — satisfied
			if container.SecurityContext.RunAsUser != nil && *container.SecurityContext.RunAsUser == 0 {
				result.Violations = append(result.Violations,
					fmt.Sprintf("%s %q in pod %q/%q: runAsUser cannot be 0 (root) when runAsNonRoot is true", containerLabel, containerName, namespace, podName))
			}
			return
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsUser != nil && *container.SecurityContext.RunAsUser == 0 {
			result.Violations = append(result.Violations,
				fmt.Sprintf("%s %q in pod %q/%q: runAsUser cannot be 0 (root)", containerLabel, containerName, namespace, podName))
			return
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsUser != nil && *container.SecurityContext.RunAsUser > 0 {
			// Container sets a non-zero runAsUser — satisfies non-root implicitly
			return
		}

		// No container-level enforcement; check pod-level
		if podRunAsNonRoot {
			// Pod-level enforces non-root, container doesn't override
			// This is acceptable
			return
		}

		// Neither pod nor container enforces non-root
		result.Violations = append(result.Violations,
			fmt.Sprintf("%s %q in pod %q/%q: runAsNonRoot must be set to true in either the pod or container security context", containerLabel, containerName, namespace, podName))
	}

	// Check regular containers
	for _, container := range spec.Containers {
		checkContainer(container.Name, container, false)
	}

	// Check init containers
	for _, container := range spec.InitContainers {
		checkContainer(container.Name, container, true)
	}
}

// validateResourceLimits ensures each container has CPU and memory limits set.
func (v *PodValidator) validateResourceLimits(result *ValidationResult, containerName string, resources corev1.ResourceRequirements) {
	if v.config.EnforceResourceLimits {
		if resources.Limits == nil {
			result.Violations = append(result.Violations,
				fmt.Sprintf("container %q: resource limits are required (CPU and memory)", containerName))
			return
		}

		// Check CPU limit
		if _, hasCPU := resources.Limits[corev1.ResourceCPU]; !hasCPU {
			result.Violations = append(result.Violations,
				fmt.Sprintf("container %q: CPU resource limit is required", containerName))
		}

		// Check memory limit
		if _, hasMemory := resources.Limits[corev1.ResourceMemory]; !hasMemory {
			result.Violations = append(result.Violations,
				fmt.Sprintf("container %q: memory resource limit is required", containerName))
		}
	}
}

// decodePod extracts a Pod from an admission request's object or oldObject.
func decodePod(request *admissionv1.AdmissionRequest) (*corev1.Pod, error) {
	if request == nil {
		return nil, fmt.Errorf("admission request is nil")
	}

	var pod corev1.Pod
	var raw []byte

	if request.Operation == admissionv1.Update {
		raw = request.OldObject.Raw
		if raw == nil {
			raw = request.Object.Raw
		}
	} else {
		raw = request.Object.Raw
	}

	if raw == nil {
		return nil, fmt.Errorf("no object data in admission request")
	}

	// Use runtime decoder for proper k8s API type handling
	decoder := scheme.Codecs.UniversalDeserializer()
	obj, _, err := decoder.Decode(raw, nil, nil)
	if err != nil {
		// Fall back to JSON unmarshal if scheme decoder fails
		if uerr := json.Unmarshal(raw, &pod); uerr != nil {
			return nil, fmt.Errorf("failed to unmarshal pod (scheme decoder: %v, json: %v): %w", err, uerr, err)
		}
	} else {
		podObj, ok := obj.(*corev1.Pod)
		if !ok {
			return nil, fmt.Errorf("decoded object is not a Pod: got %T", obj)
		}
		pod = *podObj
	}

	return &pod, nil
}

// scheme is a local runtime.Scheme initialized with the core v1 types.
var scheme = runtime.NewScheme()

func init() {
	_ = corev1.AddToScheme(scheme)
}

// GetViolationMessages returns a human-readable string of all violations.
func (r *ValidationResult) GetViolationMessages() string {
	if len(r.Violations) == 0 {
		return ""
	}
	return strings.Join(r.Violations, "; ")
}

