			fmt.Sprintf("pod %q/%q: pod security context sets runAsNonRoot=true but runAsUser=0", namespace, podName))
	}

	// Helper function to check a single container
	checkContainer := func(containerName string, container corev1.Container, isInit bool) {
		containerLabel := "container"
		if isInit {
			containerLabel = "init container"
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsNonRoot != nil && *container.SecurityContext.RunAsNonRoot {
			// Container explicitly sets runAsNonRoot=true
			// Check that it doesn't override with runAsUser=0
			if container.SecurityContext.RunAsUser != nil && *container.SecurityContext.RunAsUser == 0 {
				result.Violations = append(result.Violations,
					fmt.Sprintf("%s %q in pod %q/%q: runAsUser cannot be 0 (root) when runAsNonRoot is true", containerLabel, containerName, namespace, podName))
			}
			return
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsUser != nil && *container.SecurityContext.RunAsUser == 0 {
			result.Violations = append(result.Violations,
				fmt.Sprintf("%s %q in pod %q/%q: runAsUser cannot be 0 (root)", containerLabel, containerName, namespace, podName))
			return
		}

		if container.SecurityContext != nil && container.SecurityContext.RunAsUser != nil && *container.SecurityContext.RunAsUser > 0 {
			// Container sets a non-zero runAsUser — satisfies non-root implicitly
			return
		}

		// No container-level enforcement; check pod-level
		if podRunAsNonRoot {
			// Pod-level enforces non-root, container inherits it — acceptable
			return
		}

		// Neither pod nor container enforces non-root
		result.Violations = append(result.Violations,
			fmt.Sprintf("%s %q in pod %q/%q: runAsNonRoot must be set to true in either the pod or container security context", containerLabel, containerName, namespace, podName))
	}

